const DomUtils={get:(id)=>document.getElementById(id),query:(selector)=>document.querySelector(selector),queryAll:(selector)=>document.querySelectorAll(selector),addClass:(element,className)=>element.classList.add(className),removeClass:(element,className)=>element.classList.remove(className),toggleClass:(element,className)=>element.classList.toggle(className),show:(element)=>element.style.display='block',hide:(element)=>element.style.display='none',toggle:(element)=>{if(element.style.display==='none'){element.style.display='block';}else{element.style.display='none';}}};const DateUtils={format:(date,format='dd.mm.yyyy')=>{const d=new Date(date);const day=d.getDate().toString().padStart(2,'0');const month=(d.getMonth()+1).toString().padStart(2,'0');const year=d.getFullYear();return format.replace('dd',day).replace('mm',month).replace('yyyy',year);},diffDays:(date1,date2)=>{const d1=new Date(date1);const d2=new Date(date2);const diffTime=Math.abs(d2-d1);return Math.ceil(diffTime/(1000*60*60*24));},isOverdue:(date)=>{return new Date(date)<new Date();}};const Notify={show:(message,type='info',duration=3000)=>{const alert=document.createElement('div');alert.className=`alert alert-${type} fade-in`;alert.innerHTML=`
            <i class="bi bi-${type === 'success' ? 'check-circle' : 
                                 type === 'danger' ? 'exclamation-circle' :
                                 type === 'warning' ? 'exclamation-triangle' :
                                 'info-circle'}"></i>
            ${message}
        `;const container=DomUtils.query('.alerts-container')||document.body;container.appendChild(alert);setTimeout(()=>{alert.remove();},duration);},success:(message)=>Notify.show(message,'success'),error:(message)=>Notify.show(message,'danger'),warning:(message)=>Notify.show(message,'warning'),info:(message)=>Notify.show(message,'info')};const Ajax={get:async(url)=>{try{const response=await fetch(url);return await response.json();}catch(error){console.error('GET error:',error);Notify.error('Ошибка при загрузке данных');}},post:async(url,data)=>{try{const response=await fetch(url,{method:'POST',headers:{'Content-Type':'application/json','X-CSRFToken':getCookie('csrftoken')},body:JSON.stringify(data)});return await response.json();}catch(error){console.error('POST error:',error);Notify.error('Ошибка при отправке данных');}},postForm:async(url,formData)=>{try{const response=await fetch(url,{method:'POST',headers:{'X-CSRFToken':getCookie('csrftoken')},body:formData});return await response.json();}catch(error){console.error('POST Form error:',error);Notify.error('Ошибка при отправке формы');}}};function getCookie(name){let cookieValue=null;if(document.cookie&&document.cookie!==''){const cookies=document.cookie.split(';');for(let i=0;i<cookies.length;i++){const cookie=cookies[i].trim();if(cookie.substring(0,name.length+1)===(name+'=')){cookieValue=decodeURIComponent(cookie.substring(name.length+1));break;}}}
return cookieValue;}
document.addEventListener('DOMContentLoaded',()=>{console.log('Main.js loaded');const alertsContainer=document.createElement('div');alertsContainer.className='alerts-container';alertsContainer.style.cssText=`
        position: fixed;
        top: 20px;
        right: 20px;
        z-index: 9999;
        max-width: 400px;
    `;document.body.appendChild(alertsContainer);});window.DomUtils=DomUtils;window.DateUtils=DateUtils;window.Notify=Notify;window.Ajax=Ajax;;const OrgTree={expandedNodes:new Set(),toggleNode:(nodeId,element)=>{const childrenContainer=DomUtils.get(`children-${nodeId}`);const icon=element.querySelector('.toggle-icon i');if(!childrenContainer)return;if(OrgTree.expandedNodes.has(nodeId)){childrenContainer.style.display='none';if(icon)icon.className='bi bi-chevron-down';OrgTree.expandedNodes.delete(nodeId);}else{childrenContainer.style.display='flex';if(icon)icon.className='bi bi-chevron-up';OrgTree.expandedNodes.add(nodeId);}},expandAll:()=>{DomUtils.queryAll('[id^="children-"]').forEach(container=>{container.style.display='flex';});DomUtils.queryAll('.toggle-icon i').forEach(icon=>{icon.className='bi bi-chevron-up';});OrgTree.expandedNodes.clear();},collapseAll:()=>{DomUtils.queryAll('[id^="children-"]').forEach(container=>{container.style.display='none';});DomUtils.queryAll('.toggle-icon i').forEach(icon=>{icon.className='bi bi-chevron-down';});OrgTree.expandedNodes.clear();}};const MainBlocks={scienceOpen:false,organizationOpen:false,toggleScience:()=>{const container=DomUtils.get('science-container');const icon=DomUtils.query('#science-icon i');MainBlocks.scienceOpen=!MainBlocks.scienceOpen;if(MainBlocks.scienceOpen){container.style.display='block';if(icon)icon.className='bi bi-chevron-up';}else{container.style.display='none';if(icon)icon.className='bi bi-chevron-down';}},toggleOrganization:()=>{const container=DomUtils.get('organization-container');const icon=DomUtils.query('#organization-icon i');MainBlocks.organizationOpen=!MainBlocks.organizationOpen;if(MainBlocks.organizationOpen){container.style.display='block';if(icon)icon.className='bi bi-chevron-up';}else{container.style.display='none';if(icon)icon.className='bi bi-chevron-down';}}};const Staff={showDepartmentStaff:(deptId)=>{const staffList=DomUtils.get(`dept-${deptId}-staff`);if(staffList){DomUtils.toggle(staffList);}},showLabStaff:(labId)=>{const staffList=DomUtils.get(`lab-${labId}-staff`);if(staffList){DomUtils.toggle(staffList);}}};const Search={searchInput:null,init:()=>{Search.searchInput=DomUtils.get('search-input');if(Search.searchInput){Search.searchInput.addEventListener('keyup',Search.performSearch);}},performSearch:(e)=>{const term=e.target.value.toLowerCase();if(term.length<2){DomUtils.queryAll('.tree-node').forEach(node=>{node.style.display='flex';});return;}
DomUtils.queryAll('.tree-node').forEach(node=>{const name=node.querySelector('.node-name')?.textContent.toLowerCase()||'';if(name.includes(term)){node.style.display='flex';let parent=node.parentElement.closest('.tree-node');while(parent){parent.style.display='flex';parent=parent.parentElement.closest('.tree-node');}}else{node.style.display='none';}});},clear:()=>{if(Search.searchInput){Search.searchInput.value='';DomUtils.queryAll('.tree-node').forEach(node=>{node.style.display='flex';});}}};document.addEventListener('DOMContentLoaded',()=>{console.log('Organization.js loaded');Search.init();DomUtils.queryAll('[id^="children-"]').forEach(container=>{container.style.display='none';});DomUtils.queryAll('[id$="-container"]:not([id^="children-"])').forEach(container=>{if(container.id!=='science-container'&&container.id!=='organization-container'){container.style.display='none';}});});window.OrgTree=OrgTree;window.MainBlocks=MainBlocks;window.Staff=Staff;window.Search=Search;;